useEffect(() => {
  if (typeof window === 'undefined') return
  if (!flakesRef.current.length) return

  lastScrollYRef.current = window.scrollY || 0
  lastTimeRef.current = 0

  let stopped = false

  const loop = (ts) => {
    if (stopped) return

    const { w, h } = worldRef.current
    if (!w || !h) initWorld()

    if (!lastTimeRef.current) {
      lastTimeRef.current = ts
    }

    const dtMs = ts - lastTimeRef.current
    lastTimeRef.current = ts
    const dt = Math.min(0.05, Math.max(0.012, dtMs / 1000))

    const flakes = flakesRef.current
    if (!flakes.length) {
      // если компонент уже размонтирован (cleanup выставил stopped),
      // не планируем следующий кадр — иначе можно оставить "висящий" RAF
      if (!stopped) animFrameRef.current = requestAnimationFrame(loop)
      return
    }

    const bottom = h + 40
    const left = -40
    const right = w + 40

    // плавное затухание импульса (0..1)
    const now = ts
    const impulseLeft = Math.max(0, impulseUntilRef.current - now)
    const impulsePhase = Math.min(1, impulseLeft / IMPULSE_DURATION_MS)
    const targetStrength = impulsePhase
    const currentStrength = impulseStrengthRef.current
    // сглаженный переход к нужной силе
    impulseStrengthRef.current = currentStrength + (targetStrength - currentStrength) * 0.18

    const impulseK = impulseStrengthRef.current

    const tNow = nowMs()

    for (let i = 0; i < flakes.length; i += 1) {
      const f = flakes[i]
      const depthFactor = 0.4 + f.depth * 0.6

      // базовая гравитация
      f.vy += GRAVITY * depthFactor * dt

      // лёгкий боковой шум
      f.vx += (Math.random() * 2 - 1) * WIND_NOISE * dt * depthFactor

      // подавляем «бешенство» скоростей
      f.vx *= FRICTION_VX
      f.vy *= FRICTION_VY

      // плавный возврат к базовой скорости падения
      // чем меньше impulseK, тем сильнее возвращаем к baseVy
      const relax = impulseK > 0.01 ? IMPULSE_DAMPING : 0.9
      f.vy = f.vy * relax + f.baseVy * (1 - relax)

      // обновляем позицию
      f.x += f.vx * dt
      f.y += f.vy * dt

      // лёгкое покачивание
      f.swayPhase += f.swaySpeed * dt

      // вращение вокруг своей оси
      f.angle += f.spinDir * f.spinSpeed * dt
      if (f.angle > 360) f.angle -= 360
      if (f.angle < 0) f.angle += 360

      // ушли за границы — респавним сверху, НО не чаще кулдауна
      if (f.y > bottom || f.x < left || f.x > right) {
        if (tNow >= (f.nextRespawnAt || 0)) {
          respawnFlake(f, true)
        } else {
          // держим за границей, чтобы не “дёргалось” у нижней границы
          f.y = bottom + 10
        }
      }
    }

    setTick((x0) => x0 + 1)

    // если компонент уже размонтирован (cleanup выставил stopped),
    // не планируем следующий кадр
    if (!stopped) animFrameRef.current = requestAnimationFrame(loop)
  }

  animFrameRef.current = requestAnimationFrame(loop)

  return () => {
    stopped = true
    const rafId = animFrameRef.current
    animFrameRef.current = null
    if (rafId) cancelAnimationFrame(rafId)
  }
  // eslint-disable-next-line react-hooks/exhaustive-deps
}, [])

useEffect(() => {
  if (!Number.isFinite(limit)) return
  const id = setInterval(() => {
    if (document.visibilityState !== 'visible') return
    flushQuota()
  }, STATUS_REFRESH_MS)

  const onHide = () => { flushQuota() }
  window.addEventListener('pagehide', onHide)
  document.addEventListener('visibilitychange', () => {
    if (document.visibilityState === 'hidden') onHide()
  })

  return () => {
    clearInterval(id)
    window.removeEventListener('pagehide', onHide)
  }
}, [limit, flushQuota])

useEffect(() => {
  const onEdit = (e) => {
    try {
      const d = e?.detail || {}
      if (!d?.postId || typeof d?.text !== 'string') return

      setEditPostId(String(d.postId))
      setText(String(d.text))

      try {
        setComposerActive(true)
      } catch {}

      try {
        requestAnimationFrame(() => {
          const root = (composerRef && composerRef.current) || document.getElementById('forum-composer')
          if (root && root.scrollIntoView) {
            root.scrollIntoView({ behavior: 'smooth', block: 'center' })
          }
          const ta = root?.querySelector?.('.taInput') || root?.querySelector?.('textarea')
          if (ta && typeof ta.focus === 'function') ta.focus()
        })
      } catch {}

      try {
        toast?.ok?.(t?.('forum_edit_mode'))
      } catch {}
    } catch {}
  }

  if (typeof window !== 'undefined') {
    window.addEventListener('forum:edit', onEdit)
    return () => window.removeEventListener('forum:edit', onEdit)
  }
  return undefined
}, [t, toast, composerRef, setEditPostId, setText, setComposerActive])

useEffect(() => {
  const a = audioRef.current
  if (!a || !locked) return

  let removed = false

  const enableSound = async () => {
    if (!audioRef.current) return
    try {
      audioRef.current.muted = false
      await audioRef.current.play()
      setPlaying(true)
      setLocked(false)

      window.dispatchEvent(
        new CustomEvent('site-media-play', {
          detail: { source: 'bg-audio' },
        })
      )

      detach()
    } catch {}
  }

  const onGesture = () => enableSound()

  function attach() {
    if (removed) return
    window.addEventListener('pointerdown', onGesture, true)
    window.addEventListener('click', onGesture, true)
    window.addEventListener('keydown', onGesture, true)
    window.addEventListener('wheel', onGesture, { passive: true, capture: true })
    window.addEventListener('touchstart', onGesture, { passive: true, capture: true })
    window.addEventListener('touchmove', onGesture, { passive: true, capture: true })
  }

  function detach() {
    if (removed) return
    removed = true
    window.removeEventListener('pointerdown', onGesture, true)
    window.removeEventListener('click', onGesture, true)
    window.removeEventListener('keydown', onGesture, true)
    window.removeEventListener('wheel', onGesture, true)
    window.removeEventListener('touchstart', onGesture, true)
    window.removeEventListener('touchmove', onGesture, true)
  }

  attach()
  return detach
}, [locked])
